inline const PresetTapConfig& getPresetTapConfig(int presetIndex)
{
    if (presetIndex < 0 || presetIndex >= kNumPresetTapConfigs)
        return kPresetTapConfigs[0];
    return kPresetTapConfigs[presetIndex];
}
